const item = $input.first();
const message = item.json.message || {};
const tieneTexto = Boolean(message.text);
const tieneFoto = Array.isArray(message.photo) && message.photo.length > 0;
const tieneSticker = Boolean(message.sticker);
let tipoMensaje = "desconocido";
if (tieneSticker) {
 tipoMensaje = "sticker";
} else if (tieneFoto) {
 tipoMensaje = "foto_meme";
} else if (tieneTexto) {
 const texto = message.text.trim();
 if (texto.startsWith("/")) {
 tipoMensaje = "comando";
 } else {
 tipoMensaje = "texto";
 }
}
return [
 {
 json: {
 ...item.json,
 tipo_mensaje: tipoMensaje,
 chat_id: message.chat?.id || "",
 texto_usuario: message.text || "",
 tiene_sticker: tieneSticker,
 tiene_foto: tieneFoto,
 tiene_texto: tieneTexto
 }
 }
];

