const input = $input.first().json;
// 1. Extraer texto devuelto por Gemini
let raw = "";
if (
 input.candidates &&
 Array.isArray(input.candidates) &&
 input.candidates[0]?.content?.parts?.[0]?.text
) {
 raw = input.candidates[0].content.parts[0].text;
} else if (input.content?.parts?.[0]?.text) {
 raw = input.content.parts[0].text;
} else {
 raw = input.text || input.output || input.response || input.result || "";
}
if (typeof raw !== "string") {
 raw = JSON.stringify(raw);

}
// 2. Limpiar markdown si Gemini lo agregó
raw = raw
 .replace(/```json/g, "")
 .replace(/```JSON/g, "")
 .replace(/```/g, "")
 .trim();
// 3. Intentar convertir a JSON
const match = raw.match(/\{[\s\S]*\}/);
let data;
try {
 data = match ? JSON.parse(match[0]) : JSON.parse(raw);
} catch (error) {
 data = {
 descripcion_visual: "",
 texto_detectado: "",
 categoria_tematica: "otro",
 categoria_emocional: "neutral",
 tono: "",
 rasgo_predominante: "",
 instrucciones_dibujo: "",
 contiene_persona_real: "No",
 requiere_consentimiento: "No",
 estado: "ERROR",
 detalle_error: "No se pudo convertir la respuesta de Gemini a JSON"
