 "vida_universitaria",
 "tecnologia_ia",
 "relaciones_sociales",
 "cultura_digital",
 "trabajo_productividad",
 "humor_absurdo",
 "otro"
];
const categoriasEmocionales = [
 "alegria",
 "estres",
 "frustracion",
 "sarcasmo",
 "sorpresa",
 "tristeza",
 "neutral"
];
// 5. Normalizar categorías
if (!categoriasTematicas.includes(data.categoria_tematica)) {
 data.categoria_tematica = "otro";
}
if (!categoriasEmocionales.includes(data.categoria_emocional)) {
 data.categoria_emocional = "neutral";
}
// 6. Recuperar datos del flujo anterior
let entrada = {};
try {
 entrada = $("Identificar tipo de mensaje").first().json;
} catch (error) {
 entrada = {};
}

let tipoEntrada = "";
let fuente = "";
try {
 tipoEntrada = $json.tipo_entrada || entrada.tipo_mensaje || "";
 fuente = $json.fuente || "Telegram";
} catch (error) {
 tipoEntrada = "";
 fuente = "Telegram";
}
// 7. Preparar fila final
const ahora = new Date().toISOString();
return [
 {
