}

// 5. Construimos el mensaje solo con el total
const mensaje = `📊 Resumen del dataset:
Total procesados correctamente: ${totalProcesados}`;

return [
  {
    json: {
      chat_id: chatId,
      mensaje_resumen: mensaje
    }
  }
];

// Leemos todas las filas (asegúrate de que el nodo lea la hoja "stickers")
const rows = $input.all().map(item => item.json);

// Filtramos solo los que tienen estado OK
const registrosOK = rows.filter(row => row.estado === "OK");

function obtenerMasFrecuente(campo) {
  const conteo = {};
  let mayor = "sin_dato";
  let cantidad = 0;

  for (const row of registrosOK) {
    const valor = row[campo] || "sin_dato";
    conteo[valor] = (conteo[valor] || 0) + 1;

    // Identificamos el mayor al vuelo
    if (conteo[valor] > cantidad) {
      cantidad = conteo[valor];
      mayor = valor;
    }
  }
  return { valor: mayor, cantidad };
}

// Ejecutamos el conteo
const temaTop = obtenerMasFrecuente("categoria_tematica");
const emocionTop = obtenerMasFrecuente("categoria_emocional");

// Capturamos el chat_id desde el nodo Interruptor3
let chatId = "";
try {
  chatId = $("Interruptor3").first().json.mensaje.chat.id;
} catch (error) {
  chatId = "";
}

// Construimos el mensaje final
const mensaje = `🏆 TOP del Dataset:

📌 Categoría más frecuente: ${temaTop.valor}
(Aparece ${temaTop.cantidad} veces)

✨ Emoción dominante: ${emocionTop.valor}
(Aparece ${emocionTop.cantidad} veces)`;

return [
  {
    json: {
      chat_id: chatId,
      mensaje_top: mensaje
    }
  }
];
